1	import { useState } from "react";
2	import { useNavigate } from "react-router-dom";
3	import { useForm, useFieldArray } from "react-hook-form";
4	import { zodResolver } from "@hookform/resolvers/zod";
5	import { z } from "zod";
6	import { useMutation } from "@tanstack/react-query";
7	import { Loader2, Plus, Trash2, ArrowLeft } from "lucide-react";
8	import { toast } from "sonner";
9	import { Link } from "react-router-dom";
10	import { createOrder } from "@/api/endpoints/financials";
11	import apiClient from "@/api/client";
12	import type { PatientMasked } from "@/api/types/patient.types";
13	
14	const lineItemSchema = z.object({
15	  description: z.string().min(1, "Description is required"),
16	  quantity: z.coerce.number().min(1, "Quantity must be at least 1"),
17	  unit_price: z.coerce.number().min(0.01, "Price must be greater than 0"),
18	});
19	
20	const orderSchema = z.object({
21	  patient_id: z.string().min(1, "Patient is required"),
22	  line_items: z.array(lineItemSchema).min(1, "At least one line item is required"),
23	  notes: z.string().optional(),
24	});
25	
26	type OrderFormValues = z.infer<typeof orderSchema>;
27	
28	export function OrderCreatePage() {
29	  const navigate = useNavigate();
30	  const [patientSearch, setPatientSearch] = useState("");
31	  const [patientResults, setPatientResults] = useState<PatientMasked[]>([]);
32	  const [selectedPatient, setSelectedPatient] = useState<PatientMasked | null>(
33	    null
34	  );
35	  const [isSearching, setIsSearching] = useState(false);
36	
37	  const {
38	    register,
39	    control,
40	    handleSubmit,
41	    setValue,
42	    watch,
43	    formState: { errors },
44	  } = useForm<OrderFormValues>({
45	    resolver: zodResolver(orderSchema),
46	    defaultValues: {
47	      patient_id: "",
48	      line_items: [{ description: "", quantity: 1, unit_price: 0 }],
49	      notes: "",
50	    },
51	  });
52	
53	  const { fields, append, remove } = useFieldArray({
54	    control,
55	    name: "line_items",
56	  });
57	
58	  const watchedItems = watch("line_items");
59	  const runningTotal = watchedItems.reduce((sum, item) => {
60	    const qty = Number(item.quantity) || 0;
61	    const price = Number(item.unit_price) || 0;
62	    return sum + qty * price;
63	  }, 0);
64	
65	  const mutation = useMutation({
66	    mutationFn: (data: OrderFormValues) =>
67	      createOrder({
68	        patient_id: data.patient_id,
69	        line_items: data.line_items.map((li) => ({
70	          description: li.description,
71	          quantity: Number(li.quantity),
72	          unit_price: Number(li.unit_price),
73	        })),
74	        notes: data.notes,
75	      }),
76	    onSuccess: (result) => {
77	      toast.success("Order created successfully");
78	      navigate(`/financials/${result.id}`);
79	    },
80	    onError: (err: Error) => {
81	      toast.error(`Failed to create order: ${err.message}`);
82	    },
83	  });
84	
85	  async function searchPatients(query: string) {
86	    if (query.length < 2) {
87	      setPatientResults([]);
88	      return;
89	    }
90	    setIsSearching(true);
91	    try {
92	      const response = await apiClient.get("patients/", {
93	        params: { search: query },
94	      });
95	      setPatientResults(response.data.results ?? response.data ?? []);
96	    } catch {
97	      setPatientResults([]);
98	    } finally {
99	      setIsSearching(false);
100	    }
101	  }
102	
103	  function selectPatient(patient: PatientMasked) {
104	    setSelectedPatient(patient);
105	    setValue("patient_id", patient.id);
106	    setPatientSearch("");
107	    setPatientResults([]);
108	  }
109	
110	  return (
111	    <div className="space-y-6">
112	      {/* Header */}
113	      <div className="flex items-center gap-4">
114	        <Link
115	          to="/financials"
116	          className="inline-flex items-center gap-1 text-sm text-muted-foreground hover:text-foreground"
117	        >
118	          <ArrowLeft className="h-4 w-4" />
119	          Back
120	        </Link>
121	        <h1 className="text-3xl font-bold tracking-tight">Create Order</h1>
122	      </div>
123	
124	      <form
125	        onSubmit={handleSubmit((data) => mutation.mutate(data))}
126	        className="space-y-6"
127	      >
128	        {/* Patient Selector */}
129	        <div className="rounded-lg border border-border bg-card p-6 shadow-sm space-y-4">
130	          <h2 className="text-lg font-semibold">Patient</h2>
131	
132	          {selectedPatient ? (
133	            <div className="flex items-center justify-between rounded-md border border-border bg-muted/50 px-4 py-3">
134	              <div>
135	                <p className="text-sm font-medium">
136	                  {selectedPatient.name}
137	                </p>
138	                <p className="text-xs text-muted-foreground">
139	                  MRN: {selectedPatient.mrn}
140	                </p>
141	              </div>
142	              <button
143	                type="button"
144	                onClick={() => {
145	                  setSelectedPatient(null);
146	                  setValue("patient_id", "");
147	                }}
148	                className="text-sm text-muted-foreground hover:text-destructive"
149	              >
150	                Change
151	              </button>
152	            </div>
153	          ) : (
154	            <div className="relative">
155	              <input
156	                type="text"
157	                placeholder="Search patients by name or MRN..."
158	                value={patientSearch}
159	                onChange={(e) => {
160	                  setPatientSearch(e.target.value);
161	                  searchPatients(e.target.value);
162	                }}
163	                className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
164	              />
165	              {isSearching && (
166	                <Loader2 className="absolute right-3 top-2.5 h-4 w-4 animate-spin text-muted-foreground" />
167	              )}
168	              {patientResults.length > 0 && (
169	                <ul className="absolute z-10 mt-1 w-full rounded-md border border-border bg-popover shadow-md max-h-48 overflow-auto">
170	                  {patientResults.map((p) => (
171	                    <li key={p.id}>
172	                      <button
173	                        type="button"
174	                        onClick={() => selectPatient(p)}
175	                        className="w-full px-4 py-2 text-left text-sm hover:bg-accent hover:text-accent-foreground"
176	                      >
177	                        <span className="font-medium">{p.name}</span>
178	                        <span className="ml-2 text-muted-foreground">
179	                          MRN: {p.mrn}
180	                        </span>
181	                      </button>
182	                    </li>
183	                  ))}
184	                </ul>
185	              )}
186	            </div>
187	          )}
188	          {errors.patient_id && (
189	            <p className="text-sm text-destructive">
190	              {errors.patient_id.message}
191	            </p>
192	          )}
193	        </div>
194	
195	        {/* Line Items */}
196	        <div className="rounded-lg border border-border bg-card p-6 shadow-sm space-y-4">
197	          <div className="flex items-center justify-between">
198	            <h2 className="text-lg font-semibold">Line Items</h2>
199	            <button
200	              type="button"
201	              onClick={() =>
202	                append({ description: "", quantity: 1, unit_price: 0 })
203	              }
204	              className="inline-flex items-center gap-1 rounded-md bg-secondary px-3 py-1.5 text-xs font-medium text-secondary-foreground hover:bg-secondary/80"
205	            >
206	              <Plus className="h-3 w-3" />
207	              Add Item
208	            </button>
209	          </div>
210	
211	          {errors.line_items?.root && (
212	            <p className="text-sm text-destructive">
213	              {errors.line_items.root.message}
214	            </p>
215	          )}
216	
217	          <div className="space-y-3">
218	            {fields.map((field, index) => (
219	              <div
220	                key={field.id}
221	                className="grid grid-cols-[1fr_100px_120px_40px] gap-3 items-start"
222	              >
223	                <div>
224	                  <input
225	                    {...register(`line_items.${index}.description`)}
226	                    placeholder="Description"
227	                    className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
228	                  />
229	                  {errors.line_items?.[index]?.description && (
230	                    <p className="mt-1 text-xs text-destructive">
231	                      {errors.line_items[index]?.description?.message}
232	                    </p>
233	                  )}
234	                </div>
235	                <div>
236	                  <input
237	                    type="number"
238	                    min={1}
239	                    {...register(`line_items.${index}.quantity`)}
240	                    placeholder="Qty"
241	                    className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
242	                  />
243	                  {errors.line_items?.[index]?.quantity && (
244	                    <p className="mt-1 text-xs text-destructive">
245	                      {errors.line_items[index]?.quantity?.message}
246	                    </p>
247	                  )}
248	                </div>
249	                <div>
250	                  <input
251	                    type="number"
252	                    step="0.01"
253	                    min={0}
254	                    {...register(`line_items.${index}.unit_price`)}
255	                    placeholder="Unit Price"
256	                    className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
257	                  />
258	                  {errors.line_items?.[index]?.unit_price && (
259	                    <p className="mt-1 text-xs text-destructive">
260	                      {errors.line_items[index]?.unit_price?.message}
261	                    </p>
262	                  )}
263	                </div>
264	                <button
265	                  type="button"
266	                  onClick={() => fields.length > 1 && remove(index)}
267	                  disabled={fields.length <= 1}
268	                  className="mt-1 inline-flex items-center justify-center rounded-md p-2 text-muted-foreground hover:text-destructive disabled:opacity-30 disabled:cursor-not-allowed"
269	                >
270	                  <Trash2 className="h-4 w-4" />
271	                </button>
272	              </div>
273	            ))}
274	          </div>
275	
276	          {/* Running Total */}
277	          <div className="flex justify-end border-t border-border pt-4">
278	            <div className="text-right">
279	              <p className="text-sm text-muted-foreground">Total</p>
280	              <p className="text-2xl font-bold font-mono">
281	                ${runningTotal.toFixed(2)}
282	              </p>
283	            </div>
284	          </div>
285	        </div>
286	
287	        {/* Notes */}
288	        <div className="rounded-lg border border-border bg-card p-6 shadow-sm space-y-4">
289	          <h2 className="text-lg font-semibold">Notes</h2>
290	          <textarea
291	            {...register("notes")}
292	            rows={3}
293	            placeholder="Optional notes..."
294	            className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring resize-none"
295	          />
296	        </div>
297	
298	        {/* Submit */}
299	        <div className="flex justify-end">
300	          <button
301	            type="submit"
302	            disabled={mutation.isPending}
303	            className="inline-flex items-center gap-2 rounded-md bg-primary px-6 py-2 text-sm font-medium text-primary-foreground shadow hover:bg-primary/90 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring disabled:opacity-50 disabled:cursor-not-allowed"
304	          >
305	            {mutation.isPending && (
306	              <Loader2 className="h-4 w-4 animate-spin" />
307	            )}
308	            Create Order
309	          </button>
310	        </div>
311	      </form>
312	    </div>
313	  );
314	}
