1	import apiClient from "@/api/client";
2	import type {
3	  PatientMasked,
4	  PatientDetail,
5	  CreatePatientPayload,
6	  CreatePatientResponse,
7	  BreakGlassPayload,
8	  BreakGlassResponse,
9	} from "@/api/types/patient.types";
10	
11	export async function searchPatients(
12	  q: string
13	): Promise<PatientMasked[]> {
14	  const response = await apiClient.get<PatientMasked[]>(
15	    "patients/",
16	    { params: { q } }
17	  );
18	  return response.data;
19	}
20	
21	export async function createPatient(
22	  data: CreatePatientPayload
23	): Promise<CreatePatientResponse> {
24	  const response = await apiClient.post<CreatePatientResponse>("patients/create/", data);
25	  return response.data;
26	}
27	
28	export async function getPatient(id: string): Promise<PatientDetail> {
29	  const response = await apiClient.get<PatientDetail>(`patients/${id}/`);
30	  return response.data;
31	}
32	
33	export async function updatePatient(
34	  id: string,
35	  data: Partial<CreatePatientPayload>
36	): Promise<PatientDetail> {
37	  const response = await apiClient.patch<PatientDetail>(
38	    `patients/${id}/update/`,
39	    data
40	  );
41	  return response.data;
42	}
43	
44	export async function breakGlass(
45	  id: string,
46	  payload: BreakGlassPayload
47	): Promise<BreakGlassResponse> {
48	  const response = await apiClient.post<BreakGlassResponse>(
49	    `patients/${id}/break-glass/`,
50	    payload
51	  );
52	  return response.data;
53	}
