1	import { useState } from "react";
2	import { useParams, Link } from "react-router-dom";
3	import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
4	import {
5	  ArrowLeft,
6	  AlertCircle,
7	  Download,
8	  Image as ImageIcon,
9	  UserPlus,
10	  AlertTriangle,
11	  Search,
12	  X,
13	} from "lucide-react";
14	import { getMedia, downloadMedia, attachMediaToPatient } from "@/api/endpoints/media";
15	import { searchPatients } from "@/api/endpoints/patients";
16	import { useAuth } from "@/contexts/AuthContext";
17	import { hasRole } from "@/lib/roles";
18	import { cn } from "@/lib/utils";
19	import { toast } from "sonner";
20	
21	const originalityBanner: Record<
22	  string,
23	  { bg: string; text: string; label: string }
24	> = {
25	  original: {
26	    bg: "bg-green-50 border-green-200 dark:bg-green-950/50 dark:border-green-900",
27	    text: "text-green-800 dark:text-green-200",
28	    label: "Original Content",
29	  },
30	  reposted: {
31	    bg: "bg-blue-50 border-blue-200 dark:bg-blue-950/50 dark:border-blue-900",
32	    text: "text-blue-800 dark:text-blue-200",
33	    label: "Reposted Content — Authorization Required",
34	  },
35	  reposted_authorized: {
36	    bg: "bg-teal-50 border-teal-200 dark:bg-teal-950/50 dark:border-teal-900",
37	    text: "text-teal-800 dark:text-teal-200",
38	    label: "Reposted Content — Authorized with Citation",
39	  },
40	  disputed: {
41	    bg: "bg-red-50 border-red-200 dark:bg-red-950/50 dark:border-red-900",
42	    text: "text-red-800 dark:text-red-200",
43	    label: "Disputed Content",
44	  },
45	};
46	
47	export function MediaDetailPage() {
48	  const { mediaId: id } = useParams<{ mediaId: string }>();
49	  const { user } = useAuth();
50	
51	  const { data: media, isLoading, isError, error, refetch } = useQuery({
52	    queryKey: ["media", id],
53	    queryFn: () => getMedia(id!),
54	    enabled: !!id,
55	  });
56	
57	  const queryClient = useQueryClient();
58	  const [showAttachDialog, setShowAttachDialog] = useState(false);
59	  const [patientSearch, setPatientSearch] = useState("");
60	  const [patientResults, setPatientResults] = useState<{ id: string; display_name: string }[]>([]);
61	  const [searchingPatients, setSearchingPatients] = useState(false);
62	
63	  const attachMutation = useMutation({
64	    mutationFn: ({ mediaId, patientId }: { mediaId: string; patientId: string }) =>
65	      attachMediaToPatient(mediaId, patientId),
66	    onSuccess: () => {
67	      toast.success("Media attached to patient");
68	      setShowAttachDialog(false);
69	      setPatientSearch("");
70	      setPatientResults([]);
71	      queryClient.invalidateQueries({ queryKey: ["media", id] });
72	    },
73	    onError: () => {
74	      toast.error("Failed to attach media to patient");
75	    },
76	  });
77	
78	  const handlePatientSearch = async (query: string) => {
79	    setPatientSearch(query);
80	    if (query.length < 2) {
81	      setPatientResults([]);
82	      return;
83	    }
84	    setSearchingPatients(true);
85	    try {
86	      const results = await searchPatients(query);
87	      setPatientResults(
88	        results.map((p) => ({ id: p.id, display_name: p.name || p.id }))
89	      );
90	    } catch {
91	      setPatientResults([]);
92	    } finally {
93	      setSearchingPatients(false);
94	    }
95	  };
96	
97	  const handleAttachPatient = (patientId: string) => {
98	    if (!id) return;
99	    attachMutation.mutate({ mediaId: id, patientId });
100	  };
101	
102	  const handleDownload = async () => {
103	    if (!id || !media) return;
104	    try {
105	      const blob = await downloadMedia(id);
106	      const url = URL.createObjectURL(blob);
107	      const a = document.createElement("a");
108	      a.href = url;
109	      a.download = media.original_filename;
110	      a.click();
111	      URL.revokeObjectURL(url);
112	    } catch {
113	      toast.error("Failed to download file");
114	    }
115	  };
116	
117	  const isClinician = user && hasRole(user.role, ["clinician"]);
118	
119	  if (isLoading) {
120	    return (
121	      <div className="mx-auto max-w-4xl space-y-6">
122	        <div className="flex items-center gap-4">
123	          <div className="h-9 w-9 animate-pulse rounded-md bg-muted" />
124	          <div className="h-8 w-48 animate-pulse rounded bg-muted" />
125	        </div>
126	        <div className="h-12 animate-pulse rounded-lg bg-muted" />
127	        <div className="h-64 animate-pulse rounded-lg bg-muted" />
128	        <div className="h-48 animate-pulse rounded-lg bg-muted" />
129	      </div>
130	    );
131	  }
132	
133	  if (isError) {
134	    return (
135	      <div className="mx-auto max-w-4xl space-y-6">
136	        <Link
137	          to="/media"
138	          className="inline-flex items-center gap-2 text-sm text-muted-foreground hover:text-foreground"
139	        >
140	          <ArrowLeft className="h-4 w-4" /> Back to Media Library
141	        </Link>
142	        <div className="rounded-lg border border-destructive/50 bg-destructive/10 p-6">
143	          <div className="flex items-center gap-3">
144	            <AlertCircle className="h-5 w-5 text-destructive" />
145	            <div className="flex-1">
146	              <p className="font-medium text-destructive">
147	                Failed to load media
148	              </p>
149	              <p className="mt-1 text-sm text-muted-foreground">
150	                {error instanceof Error
151	                  ? error.message
152	                  : "An unexpected error occurred."}
153	              </p>
154	            </div>
155	            <button
156	              onClick={() => refetch()}
157	              className={cn(
158	                "rounded-md border border-destructive/50 px-3 py-1.5",
159	                "text-sm font-medium text-destructive hover:bg-destructive/10"
160	              )}
161	            >
162	              Retry
163	            </button>
164	          </div>
165	        </div>
166	      </div>
167	    );
168	  }
169	
170	  if (!media) return null;
171	
172	  const banner = originalityBanner[media.originality_status];
173	  const needsRepostAuth =
174	    media.originality_status === "reposted" && !media.repost_authorized;
175	
176	  return (
177	    <div className="mx-auto max-w-4xl space-y-6">
178	      {/* Header */}
179	      <div className="flex items-center gap-4">
180	        <Link
181	          to="/media"
182	          className="inline-flex h-9 w-9 items-center justify-center rounded-md border border-border hover:bg-accent"
183	        >
184	          <ArrowLeft className="h-4 w-4" />
185	        </Link>
186	        <div className="flex-1">
187	          <h1 className="text-3xl font-bold tracking-tight">
188	            {media.original_filename}
189	          </h1>
190	        </div>
191	        <button
192	          onClick={handleDownload}
193	          className={cn(
194	            "inline-flex items-center gap-2 rounded-md border border-border px-4 py-2",
195	            "text-sm font-medium hover:bg-accent"
196	          )}
197	        >
198	          <Download className="h-4 w-4" />
199	          Download
200	        </button>
201	      </div>
202	
203	      {/* Originality Banner */}
204	      {banner && (
205	        <div className={cn("rounded-lg border p-4", banner.bg)}>
206	          <p className={cn("text-center font-semibold", banner.text)}>
207	            {banner.label}
208	          </p>
209	        </div>
210	      )}
211	
212	      {/* Repost Authorization Warning */}
213	      {needsRepostAuth && (
214	        <div className="rounded-lg border border-yellow-200 bg-yellow-50 p-4 dark:border-yellow-900 dark:bg-yellow-950/50">
215	          <div className="flex items-center gap-3">
216	            <AlertTriangle className="h-5 w-5 text-yellow-600 dark:text-yellow-400" />
217	            <div className="flex-1">
218	              <p className="font-medium text-yellow-800 dark:text-yellow-200">
219	                Repost Authorization Required
220	              </p>
221	              <p className="mt-1 text-sm text-yellow-700 dark:text-yellow-300">
222	                This content has been identified as reposted. Authorization with
223	                proper citation is required.
224	              </p>
225	            </div>
226	            <Link
227	              to={`/media/${id}/repost`}
228	              className={cn(
229	                "inline-flex items-center rounded-md bg-yellow-600 px-3 py-1.5",
230	                "text-sm font-medium text-white hover:bg-yellow-700"
231	              )}
232	            >
233	              Authorize Repost
234	            </Link>
235	          </div>
236	        </div>
237	      )}
238	
239	      {/* Image Viewer */}
240	      <div className="rounded-lg border border-border bg-card p-4">
241	        <div className="flex min-h-[300px] items-center justify-center rounded-md bg-muted">
242	          {media.mime_type.startsWith("image/") ? (
243	            <img
244	              src={`/api/v1/media/${media.id}/download/`}
245	              alt={media.original_filename}
246	              className="max-h-[500px] max-w-full object-contain"
247	            />
248	          ) : (
249	            <div className="text-center">
250	              <ImageIcon className="mx-auto h-16 w-16 text-muted-foreground/40" />
251	              <p className="mt-2 text-sm text-muted-foreground">
252	                Preview not available for {media.mime_type}
